100→const GRID_SIZE = 36;
101→const REPORTABLE_ITEM_TYPES = new Set(["doodle"]);
102→const ERASER_RADIUS_PX = 18;
103→const ERASER_MOVE_THROTTLE_MS = 16;
104→const MINIMAP_WIDTH = 100;
105→
106→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
107→const getWallSizeScale = (stageWidth) => clamp(stageWidth / WALL_MAX_WIDTH, 0.25, 1);
108→
109→const INK_SPEED_MIN = 0.1;
110→const INK_SPEED_MAX = 8.0;
111→const INK_WIDTH_MIN = 0.3;
112→const INK_WIDTH_MAX = 1.5;
113→const INK_SMOOTH_FACTOR = 0.35;
114→const DOODLE_MIN_DISTANCE = 0.004;
115→const DOODLE_SMOOTH_FACTOR = 0.3;
116→
117→const speedToWidthMultiplier = (speed) => {
118→    const t = clamp((speed - INK_SPEED_MIN) / (INK_SPEED_MAX - INK_SPEED_MIN), 0, 1);
119→    return INK_WIDTH_MAX - (t * t) * (INK_WIDTH_MAX - INK_WIDTH_MIN);
120→};
121→
122→const makeInkSceneFunc = (points, widths, baseWidth, color) => (ctx, shape) => {
123→    if(points.length < 4){
124→        return;
125→    }
126→
127→    const numPts = points.length / 2;
128→    const xs = [];
129→    const ys = [];
130→    for(let i = 0; i < numPts; i++){
131→        xs.push(points[i * 2]);
132→        ys.push(points[i * 2 + 1]);
133→    }
134→
135→    ctx.strokeStyle = color;
136→    ctx.lineCap = "round";
137→    ctx.lineJoin = "round";
138→
139→    if(numPts === 2){
140→        ctx.lineWidth = baseWidth * (widths[0] ?? 1);
141→        ctx.beginPath();
142→        ctx.moveTo(xs[0], ys[0]);
143→        ctx.lineTo(xs[1], ys[1]);
144→        ctx.stroke();
145→        return;
146→    }
147→
148→    for(let i = 0; i < numPts - 1; i++){
149→        const w = widths[i] ?? widths[widths.length - 1] ?? 1;
150→        ctx.lineWidth = baseWidth * w;
151→        ctx.beginPath();
152→
153→        if(i === 0){
154→            ctx.moveTo(xs[0], ys[0]);
155→        } else {
156→            ctx.moveTo((xs[i - 1] + xs[i]) / 2, (ys[i - 1] + ys[i]) / 2);
157→        }
158→
159→        if(i === numPts - 2){
160→            ctx.quadraticCurveTo(xs[i], ys[i], xs[i + 1], ys[i + 1]);
161→        } else {
162→            ctx.quadraticCurveTo(xs[i], ys[i], (xs[i] + xs[i + 1]) / 2, (ys[i] + ys[i + 1]) / 2);
163→        }
164→
165→        ctx.stroke();
166→    }
167→
168→    const lastW = widths[widths.length - 1] ?? 1;
169→    const endR = (baseWidth * lastW) / 2;
170→    ctx.fillStyle = color;
171→    ctx.beginPath();
172→    ctx.arc(xs[numPts - 1], ys[numPts - 1], endR, 0, Math.PI * 2);
173→    ctx.fill();
174→};
175→
176→const snapToGrid = (px, gridSize = GRID_SIZE) => Math.round(px / gridSize) * gridSize;
177→
178→const sortItemsByZIndex = (items = []) => [...items].sort((a, b) => {
179→    const zDiff = (a?.z_index || 0) - (b?.z_index || 0);
180→    if(zDiff !== 0){
181→        return zDiff;
182→    }
183→
184→    const dateDiff = new Date(a?.created_at || 0) - new Date(b?.created_at || 0);
185→    if(dateDiff !== 0){
186→        return dateDiff;
187→    }
188→
189→    return String(a?.id || "").localeCompare(String(b?.id || ""));
190→});
191→
192→const upsertById = (items = [], nextItem) => {
193→    const existingIndex = items.findIndex((item) => String(item?.id) === String(nextItem?.id));
194→    if(existingIndex === -1){
195→        return [...items, nextItem];
196→    }
197→
198→    const nextItems = [...items];
199→    const previousItem = nextItems[existingIndex];
200→    nextItems[existingIndex] = {
201→        ...previousItem,
202→        ...nextItem,
203→        payload: {
204→            ...(previousItem?.payload || {}),
205→            ...(nextItem?.payload || {})
206→        },
207→        users: nextItem?.users || previousItem?.users || null
208→    };
209→    return nextItems;
210→};
211→
212→const removeById = (items = [], itemId) => items.filter((item) => String(item?.id) !== String(itemId));
213→
214→const distancePointToSegment = (px, py, x1, y1, x2, y2) => {
215→    const dx = x2 - x1;
216→    const dy = y2 - y1;
217→    if(dx === 0 && dy === 0){
218→        return Math.hypot(px - x1, py - y1);
219→    }
220→
221→    const t = clamp(((px - x1) * dx + (py - y1) * dy) / (dx * dx + dy * dy), 0, 1);
222→    const cx = x1 + t * dx;
223→    const cy = y1 + t * dy;
224→    return Math.hypot(px - cx, py - cy);
225→};
226→
227→const isPointerNearDoodle = (pointerX, pointerY, doodle, radiusPx = ERASER_RADIUS_PX) => {
228→    if(!doodle?.points || doodle.points.length < 4){
229→        return false;
230→    }
231→
232→    const strokeWidth = Math.max(1, Number(doodle.strokeWidth) || 3);
233→    const hitDistance = radiusPx + strokeWidth * 0.5;
234→
235→    const points = doodle.points;
236→    for(let i = 0; i < points.length - 2; i += 2){
237→        const dist = distancePointToSegment(
238→            pointerX,
239→            pointerY,
240→            points[i],
241→            points[i + 1],
242→            points[i + 2],
243→            points[i + 3]
244→        );
245→        if(dist <= hitDistance){
246→            return true;
247→        }
248→    }
249→
250→    return false;
251→};
252→
253→const emojiCanvasCache = new Map();
254→
255→const useEmojiImage = (emoji, resolution = 128) => {
256→    const [image, setImage] = useState(() => emojiCanvasCache.get(`${emoji}-${resolution}`) || null);
257→
258→    useEffect(() => {
259→        if(!emoji){
260→            setImage(null);
261→            return;
262→        }
263→
264→        const cacheKey = `${emoji}-${resolution}`;
265→        const cached = emojiCanvasCache.get(cacheKey);
266→        if(cached){
267→            setImage(cached);
268→            return;
269→        }
270→
271→        const canvas = document.createElement("canvas");
272→        canvas.width = resolution;
273→        canvas.height = resolution;
274→        const ctx = canvas.getContext("2d");
275→        ctx.clearRect(0, 0, resolution, resolution);
276→        ctx.textAlign = "center";
277→        ctx.textBaseline = "middle";
278→        ctx.font = `${Math.round(resolution * 0.78)}px "Segoe UI Emoji", "Apple Color Emoji", "Noto Color Emoji", sans-serif`;
279→        ctx.fillText(emoji, resolution / 2, resolution / 2);
280→
281→        const img = new window.Image();
282→        img.onload = () => {
283→            emojiCanvasCache.set(cacheKey, img);
284→            setImage(img);
285→        };
286→        img.src = canvas.toDataURL();
287→    }, [emoji, resolution]);
288→
289→    return image;
290→};
291→
292→const springBounce = (node) => {
293→    if (!node) return;
294→    node.to({ scaleX: 1.08, scaleY: 0.94, duration: 0.1, easing: Konva.Easings.EaseOut, onFinish: () => {
295→        node.to({ scaleX: 0.96, scaleY: 1.06, duration: 0.1, easing: Konva.Easings.EaseOut, onFinish: () => {
296→            node.to({ scaleX: 1, scaleY: 1, duration: 0.12, easing: Konva.Easings.EaseOut });
297→        }});
