                <Circle
                    key={i}
                    x={Math.cos(p.angle) * p.distance * eased}
                    y={Math.sin(p.angle) * p.distance * eased}
                    radius={Math.max(0.5, (p.ring === 1 ? 3.5 : 2.5) * (1 - progress))}
                    fill={p.color}
                    opacity={1 - progress}
                />
            ))}
        </Group>
    );
};

