    border: 1px solid rgba(220, 225, 220, 0.15);
    border-radius: 8px;
    padding: 0.3rem 0.7rem;
    font-size: 0.7rem;
    font-weight: 600;
    color: var(--fw-chalk-dim);
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
}

.fw-reset-zoom-btn:hover{
    background: rgba(0, 0, 0, 0.5);
    color: var(--fw-chalk);
}

.fw-minimap{
    position: absolute;
    bottom: 10px;
    left: 10px;
    width: 100px;
    background: rgba(0, 0, 0, 0.25);
    border: 1px solid rgba(220, 225, 220, 0.1);
    border-radius: 6px;
    overflow: hidden;
    cursor: pointer;
    z-index: 5;
    touch-action: none;
    user-select: none;
}

.fw-minimap-viewport{
    position: absolute;
    left: 0;
    top: 0;
    border: 2px solid var(--fw-chalk-yellow);
    background: rgba(245, 230, 163, 0.08);
    border-radius: 2px;
    pointer-events: auto;
    cursor: grab;
    will-change: transform;
