                draggable={canEdit}
                onClick={onSelect}
                onTap={onSelect}
                onDragEnd={(e) => { springBounce(e.target); onDragEnd(e); }}
                rotation={Number(item?.payload?.rotation) || 0}
                scaleX={isSelected ? 1.08 : 1}
                scaleY={isSelected ? 1.08 : 1}
                shadowBlur={isSelected ? 12 : 0}
                shadowOffsetY={isSelected ? 4 : 0}
