/* ── Step 8: Focus Mode ── */
.fw-focus-mode{
    padding: 0;
    gap: 0;
}

.fw-focus-mode .freedom-wall-canvas-shell{
    border: none;
    border-radius: 0;
    border-image: none;
}

.fw-focus-btn{
    width: 26px;
    height: 26px;
    border: 1px solid rgba(230, 225, 218, 0.12);
    background: rgba(255, 255, 255, 0.06);
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.78rem;
    color: var(--fw-chalk-dim);
    font-weight: 700;
    transition: background 0.15s, color 0.15s;
}

.fw-focus-btn:hover{
    background: rgba(255, 255, 255, 0.12);
    color: var(--fw-chalk);
}

.fw-focus-btn.is-active{
    border-color: var(--fw-chalk-yellow);
    color: var(--fw-chalk-yellow);
    background: rgba(245, 230, 163, 0.1);
}

input.old_string:
.fw-focus-btn.is-active{
    border-color: var(--fw-chalk-yellow);
    color: var(--fw-chalk-yellow);
    background: rgba(245, 230, 163, 0.1);
}

input.new_string:
.fw-focus-btn.is-active{
    border-color: var(--fw-chalk-yellow);
    color: var(--fw-chalk-yellow);
    background: rgba(245, 230, 163, 0.1);
}

/* ── UI Enhancement: Micro-interactions (Area 9) ── */
.fw-tool-btn:active:not(:disabled){
    transform: scale(0.96);
}

.fw-tool-btn::after{
    content: "";
    position: absolute;
    inset: 0;
    border-radius: inherit;
    background: radial-gradient(circle at center, rgba(245, 230, 163, 0.18) 0%, transparent 70%);
    opacity: 0;
    transition: opacity 0.15s;
    pointer-events: none;
}

.fw-tool-btn{
    position: relative;
    overflow: hidden;
}

.fw-tool-btn:active::after{
    opacity: 1;
}

.fw-stamp-btn:active,
.fw-sticker-btn:active{
    transform: scale(0.92);
}

.fw-apply-btn:active,
.fw-delete-btn:active{
    transform: scale(0.97);
}

.fw-swatch:active{
    transform: scale(0.88);
}

.fw-font-chip:active{
    transform: scale(0.95);
}

.freedom-wall-error-toast{
    animation: fw-toast-slide-down 0.3s ease-out;
}

@keyframes fw-toast-slide-down{
    from{ opacity: 0; transform: translateY(-10px); }
    to{ opacity: 1; transform: translateY(0); }
}

/* ── UI Enhancement: Header (Area 2) ── */
.freedom-wall-header{
    border-bottom: 1px solid rgba(220, 225, 220, 0.08);
    padding-bottom: 0.65rem;
}

.fw-title-chalk{
    background: linear-gradient(135deg, var(--fw-chalk) 0%, var(--fw-chalk-yellow) 60%, var(--fw-chalk-pink) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    filter: drop-shadow(0 0 8px rgba(245, 230, 163, 0.15));
}

.fw-countdown-clock{
    display: inline-block;
    animation: fw-clock-wobble 2s ease-in-out infinite;
    margin-right: 0.3rem;
}

@keyframes fw-clock-wobble{
    0%, 100%{ transform: rotate(0deg); }
    25%{ transform: rotate(8deg); }
    75%{ transform: rotate(-8deg); }
}

.fw-countdown-label{
    color: var(--fw-chalk-dim);
    font-weight: 600;
}

.fw-countdown-value{
    color: var(--fw-chalk-yellow);
    font-weight: 700;
}

.fw-active-users-pill{
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
    border: 1px solid rgba(168, 230, 163, 0.25);
    background: rgba(168, 230, 163, 0.08);
    border-radius: 999px;
    padding: 0.25rem 0.58rem;
    font-size: 0.68rem;
    color: var(--fw-chalk-green);
    font-weight: 600;
    margin-top: 0.3rem;
}

.fw-active-dot{
    width: 7px;
    height: 7px;
    border-radius: 50%;
    background: var(--fw-chalk-green);
    animation: fw-dot-pulse 1.5s ease-in-out infinite;
}

@keyframes fw-dot-pulse{
    0%, 100%{ opacity: 1; transform: scale(1); }
    50%{ opacity: 0.6; transform: scale(0.75); }
}

/* ── UI Enhancement: Toolbar (Area 3) ── */
.fw-tool-emoji{
    margin-right: 0.25rem;
