}

.fw-draft-note-actions{
    border-top: 1px solid rgba(220, 225, 220, 0.08);
    padding-top: 0.5rem;
}

/* Custom range slider */
.freedom-wall-page input[type="range"]::-webkit-slider-thumb{
    -webkit-appearance: none;
    appearance: none;
    width: 16px;
    height: 16px;
    border-radius: 50%;
    background: var(--fw-chalk-yellow);
    border: 2px solid rgba(0, 0, 0, 0.25);
    cursor: pointer;
    box-shadow: 0 0 6px rgba(245, 230, 163, 0.3);
    transition: transform 0.12s, box-shadow 0.12s;
}

.freedom-wall-page input[type="range"]::-webkit-slider-thumb:hover{
    transform: scale(1.2);
    box-shadow: 0 0 10px rgba(245, 230, 163, 0.45);
}

.freedom-wall-page input[type="range"]::-moz-range-thumb{
    width: 16px;
