.freedom-wall-page input[type="range"]::-moz-range-thumb:hover{
    transform: scale(1.2);
    box-shadow: 0 0 10px rgba(245, 230, 163, 0.45);
}

/* ── UI Enhancement: Canvas Frame (Area 5) ── */
.freedom-wall-canvas-shell::before{
    content: "";
    position: absolute;
    inset: 0;
    border-radius: 4px;
    background:
        radial-gradient(ellipse at 5% 5%, rgba(200, 195, 185, 0.04) 0%, transparent 40%),
        radial-gradient(ellipse at 95% 5%, rgba(200, 195, 185, 0.03) 0%, transparent 35%);
    pointer-events: none;
    z-index: 3;
    animation: fw-chalk-dust-drift 12s ease-in-out infinite alternate;
}

@keyframes fw-chalk-dust-drift{
    0%{ opacity: 1; }
    50%{ opacity: 0.6; }
    100%{ opacity: 1; }
}

/* ── UI Enhancement: Footer (Area 6) ── */
.freedom-wall-footer{
    border-top: 1px solid rgba(220, 225, 220, 0.08);
    padding-top: 0.5rem;
}

.fw-footer-count strong{
    color: var(--fw-chalk);
}

.fw-sync-indicator{
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
}

.fw-sync-dot{
    width: 7px;
    height: 7px;
    border-radius: 50%;
    flex-shrink: 0;
}

.fw-sync-dot.is-synced{
    background: var(--fw-chalk-green);
    box-shadow: 0 0 6px rgba(168, 230, 163, 0.35);
}

.fw-sync-dot.is-syncing{
    background: var(--fw-chalk-yellow);
    animation: fw-sync-pulse 1s ease-in-out infinite;
}

@keyframes fw-sync-pulse{
    0%, 100%{ opacity: 1; transform: scale(1); }
    50%{ opacity: 0.5; transform: scale(0.7); }
}

/* ── UI Enhancement: Loading & Error (Area 7) ── */
.fw-loading-skeleton{
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.75rem;
    padding: 3rem 2rem;
}

.fw-skeleton-bar{
    height: 10px;
    border-radius: 6px;
    background: linear-gradient(
        90deg,
        rgba(200, 195, 185, 0.06) 25%,
        rgba(200, 195, 185, 0.14) 50%,
        rgba(200, 195, 185, 0.06) 75%
    );
    background-size: 200% 100%;
    animation: fw-shimmer 1.5s ease-in-out infinite;
}

.fw-skeleton-bar:nth-child(1){ width: 60%; }
.fw-skeleton-bar:nth-child(2){ width: 45%; }
.fw-skeleton-bar:nth-child(3){ width: 30%; }

.fw-skeleton-text{
    color: var(--fw-chalk-faint);
    font-size: 0.75rem;
    margin-top: 0.4rem;
    animation: fw-shimmer 1.5s ease-in-out infinite;
}

@keyframes fw-shimmer{
    0%{ background-position: 200% 0; opacity: 0.7; }
    50%{ opacity: 1; }
    100%{ background-position: -200% 0; opacity: 0.7; }
}

.fw-error-state{
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    padding: 2rem;
    text-align: center;
    color: var(--fw-chalk-dim);
}

.fw-error-icon{
    font-size: 1.8rem;
    filter: drop-shadow(0 0 6px rgba(242, 167, 179, 0.2));
}

.fw-error-hint{
    font-size: 0.72rem;
    color: var(--fw-chalk-faint);
}

/* ── UI Enhancement: Modal (Area 8) ── */
.fw-modal-btn{
    min-width: 90px;
    transition: background 0.15s, transform 0.1s;
}

.fw-modal-btn:hover{
    transform: translateY(-1px);
}

.fw-modal-btn:active{
    transform: translateY(0) scale(0.98);
}

