}

.fw-readonly-pill{
    width: fit-content;
    border: 1px solid rgba(220, 225, 220, 0.12);
    background: rgba(0, 0, 0, 0.15);
    border-radius: 999px;
    padding: 0.28rem 0.7rem;
    font-size: 0.68rem;
    color: var(--fw-chalk-faint);
