.freedom-wall-canvas-shell{
    position: relative;
    width: 100%;
    border: 4px solid var(--fw-frame);
    background: var(--fw-board-dark);
    border-radius: 6px;
    padding: 6px;
    box-sizing: border-box;
    overflow: hidden;
    touch-action: none;
    box-shadow:
        inset 0 2px 12px rgba(0, 0, 0, 0.15),
        inset 0 0 24px rgba(0, 0, 0, 0.1),
        0 4px 20px rgba(0, 0, 0, 0.35),
        0 1px 3px rgba(0, 0, 0, 0.15);
    border-image:
        linear-gradient(
            135deg,
            #6e6560 0%,
            #807870 15%,
            #5a5450 30%,
            #6e6862 50%,
            #5c5550 70%,
            #6e6560 85%,
            #5a5450 100%
        ) 1;
    animation: fw-ambient-pulse 6s ease-in-out infinite;
}

.freedom-wall-canvas-shell::after{
    content: "";
    position: absolute;
    inset: 0;
    border-radius: 4px;
    background: radial-gradient(
        ellipse at 50% 50%,
        transparent 55%,
        rgba(0, 0, 0, 0.18) 100%
    );
