    50%{ box-shadow: inset 0 2px 14px rgba(0,0,0,0.18), inset 0 0 28px rgba(0,0,0,0.12), 0 5px 24px rgba(0,0,0,0.38), 0 1px 4px rgba(0,0,0,0.18); }
}

.freedom-wall-canvas-shell.is-eraser-mode,
.freedom-wall-canvas-shell.is-eraser-mode .konvajs-content,
