}

.fw-draft-note-actions{
    display: flex;
    gap: 0.5rem;
}

.fw-draft-note-actions .fw-apply-btn:disabled{
    opacity: 0.35;
    cursor: not-allowed;
}

.freedom-wall-error-toast{
    padding: 0.45rem 0.75rem;
    border-radius: 10px;
    background: rgba(242, 167, 179, 0.12);
    border: 1px solid rgba(242, 167, 179, 0.3);
    color: var(--fw-chalk-pink);
    font-size: 0.74rem;
    font-weight: 600;
}

.fw-modal-backdrop{
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.46);
    backdrop-filter: blur(2px);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 60;
    padding: 1rem;
    box-sizing: border-box;
}

.fw-modal-card{
    width: min(420px, 100%);
    border: 1px solid rgba(220, 225, 220, 0.18);
    background: rgba(24, 22, 20, 0.95);
    border-radius: 14px;
    padding: 0.9rem;
    box-shadow: 0 14px 40px rgba(0, 0, 0, 0.38);
    display: flex;
    flex-direction: column;
    gap: 0.55rem;
}

.fw-modal-card h4{
    margin: 0;
    color: var(--fw-chalk);
    font-size: 0.95rem;
}

.fw-modal-card p{
    margin: 0;
    color: var(--fw-chalk-dim);
    font-size: 0.78rem;
    line-height: 1.4;
}

.fw-modal-actions{
    display: flex;
    gap: 0.5rem;
    justify-content: flex-end;
    flex-wrap: wrap;
}

.freedom-wall-footer{
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: var(--fw-chalk-faint);
    font-size: 0.7rem;
    font-weight: 600;
}

.fw-zoom-controls{
    position: absolute;
    bottom: 10px;
    right: 25px;
    display: flex;
    align-items: center;
    gap: 4px;
    background: rgba(0, 0, 0, 0.35);
    backdrop-filter: blur(4px);
    border: 1px solid rgba(220, 225, 220, 0.1);
    border-radius: 8px;
    padding: 3px 6px;
    z-index: 5;
    font-size: 0.7rem;
}

.fw-zoom-controls button{
    width: 26px;
    height: 26px;
    border: 1px solid rgba(220, 225, 220, 0.12);
    background: rgba(255, 255, 255, 0.06);
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.82rem;
    color: var(--fw-chalk-dim);
    font-weight: 700;
    transition: background 0.15s, color 0.15s;
}

.fw-zoom-controls button:hover{
    background: rgba(255, 255, 255, 0.12);
    color: var(--fw-chalk);
}

.fw-zoom-level{
    min-width: 36px;
    text-align: center;
    color: var(--fw-chalk-faint);
    font-weight: 600;
    font-variant-numeric: tabular-nums;
}

.fw-reset-zoom-btn{
    position: absolute;
    bottom: 10px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 5;
    background: rgba(0, 0, 0, 0.35);
    backdrop-filter: blur(4px);
    border: 1px solid rgba(220, 225, 220, 0.15);
    border-radius: 8px;
    padding: 0.3rem 0.7rem;
    font-size: 0.7rem;
    font-weight: 600;
    color: var(--fw-chalk-dim);
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
}

.fw-reset-zoom-btn:hover{
    background: rgba(0, 0, 0, 0.5);
    color: var(--fw-chalk);
}

.fw-minimap{
    position: absolute;
    bottom: 10px;
    left: 10px;
    width: 100px;
    background: rgba(0, 0, 0, 0.25);
    border: 1px solid rgba(220, 225, 220, 0.1);
    border-radius: 6px;
    overflow: hidden;
    cursor: pointer;
    z-index: 5;
    touch-action: none;
    user-select: none;
}

.fw-minimap-viewport{
    position: absolute;
    left: 0;
    top: 0;
    border: 2px solid var(--fw-chalk-yellow);
    background: rgba(245, 230, 163, 0.08);
    border-radius: 2px;
    pointer-events: auto;
    cursor: grab;
    will-change: transform;
}

@media (max-width: 480px){
    .freedom-wall-page{
        padding: 0.5rem;
        padding-bottom: 5rem;
    }

    .freedom-wall-week-pill{
        width: 100%;
        border-radius: 10px;
    }

    .freedom-wall-week-shell{
        width: 100%;
        align-items: flex-start;
    }

    .freedom-wall-tool-controls{
        flex-direction: column;
        align-items: flex-start;
    }

    .freedom-wall-tool-controls input[type="text"],
    .freedom-wall-tool-controls select{
        width: 100%;
    }

    .fw-draft-note-controls{
        flex-direction: column;
        align-items: flex-start;
    }

    .fw-dock-controls-popover{
        max-width: 100%;
        min-width: 0;
    }
}

/* Accent for range inputs */
.freedom-wall-page input[type="range"]{
