                <span>
                    {createItemMutation.isPending || updateItemMutation.isPending || deleteItemMutation.isPending
                    || reportItemMutation.isPending
                    || clearMyDoodlesMutation.isPending
                        ? "Syncing..."
                        : "Synced"}
                </span>
            </div>}
        </div>
    );
};

export default FreedomWallPage;

