    }, [clampStagePosition, minimapHeight, stageHeight, stageScale, stageWidth]);

    const flushPendingMinimapPan = useCallback(() => {
        minimapFrameRef.current = null;
        const pending = minimapPendingRef.current;
        if(!pending){
