        isActive: false,
        pointerId: null,
        offsetX: 0,
        offsetY: 0,
        consumedClick: false
    });
    const minimapPendingRef = useRef(null);
    const minimapFrameRef = useRef(null);
    const minimapSuppressClickRef = useRef(false);

    const authToken = session?.access_token || null;
