        const prevPoints = draftDoodleRef.current;
        const lastPtX = prevPoints[prevPoints.length - 2];
        const lastPtY = prevPoints[prevPoints.length - 1];
        const ptDx = normalizedPointer.x - lastPtX;
        const ptDy = normalizedPointer.y - lastPtY;
        if(Math.sqrt(ptDx * ptDx + ptDy * ptDy) < DOODLE_MIN_DISTANCE){
            return;
        }

        const smoothX = lastPtX + (normalizedPointer.x - lastPtX) * (1 - DOODLE_SMOOTH_FACTOR);
        const smoothY = lastPtY + (normalizedPointer.y - lastPtY) * (1 - DOODLE_SMOOTH_FACTOR);

        const now = performance.now();
        const last = lastDoodlePointRef.current;
        if(last){
            const dx = (smoothX - last.x) * stageWidth;
            const dy = (smoothY - last.y) * stageHeight;
            const dist = Math.sqrt(dx * dx + dy * dy);
            const dt = Math.max(now - last.t, 1);
            const speed = dist / dt;
            const rawWidth = speedToWidthMultiplier(speed);
            const prev = draftWidthsRef.current.length > 0
                ? draftWidthsRef.current[draftWidthsRef.current.length - 1]
                : rawWidth;
            const smoothed = prev + INK_SMOOTH_FACTOR * (rawWidth - prev);
            draftWidthsRef.current.push(smoothed);
        }
        lastDoodlePointRef.current = { x: smoothX, y: smoothY, t: now };

        const nextPoints = [...prevPoints, smoothX, smoothY];
        draftDoodleRef.current = nextPoints;
        setDraftDoodlePoints(nextPoints);
        if(event?.evt?.cancelable){
            event.evt.preventDefault();
        }
    };

    const handleStagePointerUp = (event) => {
        if(isPinchingRef.current){
            isPinchingRef.current = false;
            lastPinchDistRef.current = null;
            lastPinchCenterRef.current = null;
            return;
        }

        if(activeTool === "eraser"){
            setIsErasing(false);
            erasedThisStrokeRef.current.clear();
            return;
        }

        if(activeTool !== "doodle"){
            return;
        }

        const points = draftDoodleRef.current
            .map((point) => Number(point))
            .filter((point) => !Number.isNaN(point))
            .map((point) => clamp(point, 0, 1));

        if(points.length >= 4){
            const normalizedPoints = points.length % 2 === 0 ? points : points.slice(0, -1);
            const numSegments = normalizedPoints.length / 2 - 1;
            const widths = draftWidthsRef.current.slice(0, numSegments);
            createWallItem("doodle", {
                points: normalizedPoints,
                widths: widths.length > 0 ? widths : undefined,
                color: doodleColor,
                size: doodleSize
            });
        }

        setIsDrawing(false);
        setDraftDoodlePoints([]);
        draftDoodleRef.current = [];
        draftWidthsRef.current = [];
        lastDoodlePointRef.current = null;
    };

    const handleDeleteSelectedItem = () => {
