    const y = clamp((Number(item?.payload?.y) || 0.5) * stageHeight, 0, Math.max(0, stageHeight - size));
    const showBorder = isDraft || isSelected;

    if(!image){
        return null;
    }

    return (
        <>
            <KonvaImage
                x={x}
                y={y}
                width={size}
                height={size}
                image={image}
                draggable={canEdit}
                onClick={onSelect}
                onTap={onSelect}
                onDragEnd={(e) => { springBounce(e.target); onDragEnd(e); }}
                rotation={Number(item?.payload?.rotation) || 0}
