                    };
                });
            });
            return {previousItem: previousItem};
        },
        onSuccess: (response) => {
            const updatedItem = response?.item;
            if(!updatedItem?.id){
                return;
            }

            setItemsCache((items) => upsertById(items, updatedItem));
        },
        onError: (_error, variables, context) => {
            if(!context?.previousItem){
                return;
