        lastCursorBroadcastRef.current = now;

        const stage = event.target.getStage();
        const pointer = stage?.getPointerPosition();
        if(!pointer) return;

        const logicalX = (pointer.x - stage.x()) / stage.scaleX();
        const logicalY = (pointer.y - stage.y()) / stage.scaleY();

