            fontStyle: draftNote.fontStyle || "normal",
            fontColor: draftNote.fontColor || "#1f2937",
            bgColor: draftNote.bgColor || "#fff4a8",
            fontSize: clamp(Number(draftNote.fontSize) || 16, 10, 64)
