    useEffect(() => {
        const interval = setInterval(() => {
            const now = Date.now();
            setRemoteCursors((prev) => {
                const next = {};
                let changed = false;
                for(const [key, cursor] of Object.entries(prev)){
                    if(now - cursor.updatedAt < 3000){
                        next[key] = cursor;
                    } else {
                        changed = true;
