    const y = clamp((Number(item?.payload?.y) || 0.5) * stageHeight, 0, Math.max(0, stageHeight - size));
    const showBorder = isDraft || isSelected;

    if(!image){
        return null;
    }

    return (
        <>
            <KonvaImage
                x={x}
                y={y}
                width={size}
                height={size}
                image={image}
                draggable={canEdit}
                onClick={onSelect}
                onTap={onSelect}
                onDragEnd={(e) => { springBounce(e.target); onDragEnd(e); }}
                rotation={Number(item?.payload?.rotation) || 0}
                scaleX={isSelected ? 1.08 : 1}
                scaleY={isSelected ? 1.08 : 1}
                shadowBlur={isSelected ? 12 : 0}
                shadowOffsetY={isSelected ? 4 : 0}
                shadowColor="rgba(0,0,0,0.3)"
            />
            {showBorder && (
                <Rect
                    x={x}
                    y={y}
                    width={size}
                    height={size}
                    stroke={isDraft ? "#a21caf" : "#4f46e5"}
                    strokeWidth={2}
                    dash={[6, 4]}
                    listening={false}
                />
            )}
