        }

        if(item?.item_type === "stamp"){
            return (
                <StampNode
                    key={item.id}
                    item={item}
                    stageWidth={stageWidth}
                    stageHeight={stageHeight}
                    canEdit={canEditItem}
                    isSelected={isSelected}
                    onSelect={handleSelectItem}
                    onDragEnd={(event) => moveItemFromDrag(item, event)}
                />
            );
        }

        if(item?.item_type === "note"){
            return (
                <NoteNode
                    key={item.id}
                    item={item}
                    stageWidth={stageWidth}
                    stageHeight={stageHeight}
                    canEdit={canEditItem}
                    isSelected={isSelected}
                    onSelect={handleSelectItem}
                    onDragEnd={(event) => moveItemFromDrag(item, event)}
                />
