                        </div>
                        <span className="fw-label">Click canvas to place</span>
                    </div>
                )}

                {!isTimeCapsuleMode && activeTool === "note" && !draftNote && (
                    <div className="freedom-wall-tool-controls">
                        <span className="fw-label">Click canvas to place a note</span>
                    </div>
