                {!canWrite && (
                    <div className="fw-readonly-pill">
                        View only. Log in to add items.
                    </div>
                )}

                {isTimeCapsuleMode && (
                    <div className="fw-readonly-pill">
                        Time Capsule mode is view-only.
                    </div>
