                {canWrite && !isTimeCapsuleMode && (
                    <div className="freedom-wall-tool-controls">
                        <button
                            type="button"
                            className="fw-delete-btn"
                            onClick={handleClearMyDoodles}
                            disabled={!activeWeekId || clearMyDoodlesMutation.isPending || myDoodleCount < 1}
