                                    <button
                                        key={stickerKey}
                                        type="button"
                                        className={`fw-stamp-btn fw-sticker-btn ${draftSticker.sticker === stickerKey ? "is-active" : ""}`}
                                        onClick={() => setDraftSticker((prev) => ({...prev, sticker: stickerKey}))}
