const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
const getWallSizeScale = (stageWidth) => clamp(stageWidth / WALL_MAX_WIDTH, 0.25, 1);

const INK_SPEED_MIN = 0.1;
const INK_SPEED_MAX = 8.0;
const INK_WIDTH_MIN = 0.3;
const INK_WIDTH_MAX = 1.5;
const INK_SMOOTH_FACTOR = 0.35;
const DOODLE_MIN_DISTANCE = 0.004;
const DOODLE_SMOOTH_FACTOR = 0.3;

const speedToWidthMultiplier = (speed) => {
    const t = clamp((speed - INK_SPEED_MIN) / (INK_SPEED_MAX - INK_SPEED_MIN), 0, 1);
    return INK_WIDTH_MAX - (t * t) * (INK_WIDTH_MAX - INK_WIDTH_MIN);
};

const makeInkSceneFunc = (points, widths, baseWidth, color) => (ctx, shape) => {
    if(points.length < 4){
        return;
    }

    const numPts = points.length / 2;
    const xs = [];
    const ys = [];
    for(let i = 0; i < numPts; i++){
        xs.push(points[i * 2]);
        ys.push(points[i * 2 + 1]);
    }

    ctx.strokeStyle = color;
    ctx.lineCap = "round";
    ctx.lineJoin = "round";

    if(numPts === 2){
        ctx.lineWidth = baseWidth * (widths[0] ?? 1);
        ctx.beginPath();
        ctx.moveTo(xs[0], ys[0]);
        ctx.lineTo(xs[1], ys[1]);
        ctx.stroke();
        return;
    }

    for(let i = 0; i < numPts - 1; i++){
        const w = widths[i] ?? widths[widths.length - 1] ?? 1;
        ctx.lineWidth = baseWidth * w;
        ctx.beginPath();

        if(i === 0){
            ctx.moveTo(xs[0], ys[0]);
        } else {
            ctx.moveTo((xs[i - 1] + xs[i]) / 2, (ys[i - 1] + ys[i]) / 2);
        }

        if(i === numPts - 2){
            ctx.quadraticCurveTo(xs[i], ys[i], xs[i + 1], ys[i + 1]);
        } else {
            ctx.quadraticCurveTo(xs[i], ys[i], (xs[i] + xs[i + 1]) / 2, (ys[i] + ys[i + 1]) / 2);
        }

        ctx.stroke();
    }

    const lastW = widths[widths.length - 1] ?? 1;
    const endR = (baseWidth * lastW) / 2;
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(xs[numPts - 1], ys[numPts - 1], endR, 0, Math.PI * 2);
    ctx.fill();
};

const snapToGrid = (px, gridSize = GRID_SIZE) => Math.round(px / gridSize) * gridSize;

const sortItemsByZIndex = (items = []) => [...items].sort((a, b) => {
    const zDiff = (a?.z_index || 0) - (b?.z_index || 0);
    if(zDiff !== 0){
        return zDiff;
    }

    const dateDiff = new Date(a?.created_at || 0) - new Date(b?.created_at || 0);
    if(dateDiff !== 0){
        return dateDiff;
    }

    return String(a?.id || "").localeCompare(String(b?.id || ""));
});

const upsertById = (items = [], nextItem) => {
    const existingIndex = items.findIndex((item) => String(item?.id) === String(nextItem?.id));
    if(existingIndex === -1){
        return [...items, nextItem];
    }

    const nextItems = [...items];
    const previousItem = nextItems[existingIndex];
    nextItems[existingIndex] = {
        ...previousItem,
        ...nextItem,
        payload: {
            ...(previousItem?.payload || {}),
            ...(nextItem?.payload || {})
        },
        users: nextItem?.users || previousItem?.users || null
    };
    return nextItems;
};

const removeById = (items = [], itemId) => items.filter((item) => String(item?.id) !== String(itemId));

const distancePointToSegment = (px, py, x1, y1, x2, y2) => {
    const dx = x2 - x1;
    const dy = y2 - y1;
    if(dx === 0 && dy === 0){
        return Math.hypot(px - x1, py - y1);
    }

    const t = clamp(((px - x1) * dx + (py - y1) * dy) / (dx * dx + dy * dy), 0, 1);
    const cx = x1 + t * dx;
    const cy = y1 + t * dy;
    return Math.hypot(px - cx, py - cy);
};

const isPointerNearDoodle = (pointerX, pointerY, doodle, radiusPx = ERASER_RADIUS_PX) => {
    if(!doodle?.points || doodle.points.length < 4){
        return false;
    }

    const strokeWidth = Math.max(1, Number(doodle.strokeWidth) || 3);
    const hitDistance = radiusPx + strokeWidth * 0.5;

    const points = doodle.points;
    for(let i = 0; i < points.length - 2; i += 2){
        const dist = distancePointToSegment(
            pointerX,
            pointerY,
            points[i],
            points[i + 1],
            points[i + 2],
            points[i + 3]
        );
        if(dist <= hitDistance){
            return true;
        }
    }

    return false;
};

const emojiCanvasCache = new Map();

const useEmojiImage = (emoji, resolution = 128) => {
    const [image, setImage] = useState(() => emojiCanvasCache.get(`${emoji}-${resolution}`) || null);

    useEffect(() => {
        if(!emoji){
            setImage(null);
            return;
        }

        const cacheKey = `${emoji}-${resolution}`;
        const cached = emojiCanvasCache.get(cacheKey);
        if(cached){
            setImage(cached);
            return;
        }

        const canvas = document.createElement("canvas");
        canvas.width = resolution;
        canvas.height = resolution;
        const ctx = canvas.getContext("2d");
        ctx.clearRect(0, 0, resolution, resolution);
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.font = `${Math.round(resolution * 0.78)}px "Segoe UI Emoji", "Apple Color Emoji", "Noto Color Emoji", sans-serif`;
        ctx.fillText(emoji, resolution / 2, resolution / 2);

        const img = new window.Image();
        img.onload = () => {
            emojiCanvasCache.set(cacheKey, img);
            setImage(img);
        };
        img.src = canvas.toDataURL();
    }, [emoji, resolution]);

    return image;
};

const springBounce = (node) => {
    if (!node) return;
    node.to({ scaleX: 1.08, scaleY: 0.94, duration: 0.1, easing: Konva.Easings.EaseOut, onFinish: () => {
        node.to({ scaleX: 0.96, scaleY: 1.06, duration: 0.1, easing: Konva.Easings.EaseOut, onFinish: () => {
            node.to({ scaleX: 1, scaleY: 1, duration: 0.12, easing: Konva.Easings.EaseOut });
        }});
    }});
