        return () => {
            if(realtimeChannelRef.current){
                realtimeChannelRef.current.send({
                    type: "broadcast",
                    event: "cursor-leave",
                    payload: {clientId: clientIdRef.current}
                });
            }
            supabase.removeChannel(channel);
            realtimeChannelRef.current = null;
